import { Navbar as BsNavbar, Nav, Container } from 'react-bootstrap';
import { NavLink } from 'react-router-dom';

function Navbar() {
  return (
    <BsNavbar bg="dark" variant="dark" expand="lg">
      <Container>
        <BsNavbar.Brand as={NavLink} to="/">eTiskárna</BsNavbar.Brand>
        <BsNavbar.Toggle aria-controls="main-nav" />
        <BsNavbar.Collapse id="main-nav">
          <Nav className="ms-auto">
            <Nav.Link as={NavLink} to="/">Domů</Nav.Link>
            <Nav.Link as={NavLink} to="/katalog">Katalog produktů</Nav.Link>
            <Nav.Link as={NavLink} to="/sluzby">Naše služby</Nav.Link>
            <Nav.Link as={NavLink} to="/kontakt">Kontakt</Nav.Link>
            <Nav.Link as={NavLink} to="/poptavka" className="btn btn-primary text-white ms-2 px-3">
              Poptávka
            </Nav.Link>
          </Nav>
        </BsNavbar.Collapse>
      </Container>
    </BsNavbar>
  );
}

export default Navbar;
